package ui.student;
import javax.swing.*;import java.awt.*;import controller.StudentController;import model.Student;import util.*;
public class StudentProfilePanel extends JPanel{ JTextField full=UITheme.textField(),edu=UITheme.textField(),skills=UITheme.textField(),field=UITheme.textField(),city=UITheme.textField(),avail=UITheme.textField(),phone=UITheme.textField(); StudentController c=new StudentController(); public StudentProfilePanel(){ setBackground(UITheme.BG); setLayout(new GridLayout(0,1,0,8)); add(UITheme.title("Manage Profile")); String[] labs={"Full Name","Education","Skills comma separated","Field of Study","City","Availability","Phone"}; JTextField[] fs={full,edu,skills,field,city,avail,phone}; for(int i=0;i<labs.length;i++){add(UITheme.label(labs[i]));add(fs[i]);} JButton save=UITheme.button("Save Profile"); add(save); load(); save.addActionListener(e->save()); } void load(){ Student s=c.getProfile(Session.getUserId()); if(s!=null){ full.setText(s.getFullName()); edu.setText(s.getEducation()); skills.setText(s.getSkills()); field.setText(s.getFieldOfStudy()); city.setText(s.getCity()); avail.setText(s.getAvailability()); phone.setText(s.getPhone()); }} void save(){ Student s=c.getProfile(Session.getUserId()); if(s==null)return; s.setFullName(full.getText());s.setEducation(edu.getText());s.setSkills(skills.getText());s.setFieldOfStudy(field.getText());s.setCity(city.getText());s.setAvailability(avail.getText());s.setPhone(phone.getText()); DialogUtil.success(this,c.updateProfile(s)?"Profile updated":"Update failed"); }}
